ON CONFLICT (public_id) DO UPDATE SET
  category = EXCLUDED.category,
  name = EXCLUDED.name,
  manufacturer = EXCLUDED.manufacturer,
  price = EXCLUDED.price,
  status = EXCLUDED.status,
  attributes = EXCLUDED.attributes,
  updated_at = now();

INSERT INTO price_snapshots (
  part_id,
  price,
  source,
  collected_at,
  raw_payload
)
SELECT p.id,
       p.price,
       'MANUAL_CURRENT_LINEUP',
       '2026-06-29T16:25:00Z',
       jsonb_build_object(
         'source', 'manual-current-cooler-lineup',
         'collector', 'prototype-seed',
         'catalogGeneration', 'CURRENT_2026_06',
         'partPublicId', p.public_id::text,
         'keyword', coalesce(p.attributes #>> '{externalSources,naver,keyword}', p.name),
         'backupOnly', true,
         'shippingIncluded', false,
         'couponIncluded', false
       )
FROM parts p
WHERE p.public_id IN (
  '00000000-0000-4000-8000-000000011701',
  '00000000-0000-4000-8000-000000011702',
  '00000000-0000-4000-8000-000000011703',
  '00000000-0000-4000-8000-000000011704',
  '00000000-0000-4000-8000-000000011705',
  '00000000-0000-4000-8000-000000011706',
  '00000000-0000-4000-8000-000000011707',
  '00000000-0000-4000-8000-000000011708',
  '00000000-0000-4000-8000-000000011709',
  '00000000-0000-4000-8000-000000011710'
);

SELECT setval(pg_get_serial_sequence('parts', 'id'), (SELECT max(id) FROM parts));
SELECT setval(pg_get_serial_sequence('price_snapshots', 'id'), (SELECT max(id) FROM price_snapshots));
